{
  "$schema": "https://e-menum.net/schemas/module-v1.json",
  "id": "notification",
  "name": "Notification Module",
  "version": "1.0.0",
  "description": "Core notification module providing email and in-app notification management for E-Menum",

  "type": "core",
  "category": "system",

  "author": {
    "name": "E-Menum Team",
    "email": "dev@e-menum.net"
  },

  "compatibility": {
    "platform": ">=1.0.0",
    "node": ">=20.0.0"
  },

  "dependencies": {
    "modules": ["auth", "organization", "user"],
    "optional": []
  },

  "provides": {
    "routes": true,
    "events": [
      "notification.created",
      "notification.read",
      "notification.deleted",
      "notification.broadcast"
    ],
    "hooks": [
      "beforeSend",
      "afterSend",
      "beforeRead",
      "afterRead"
    ],
    "permissions": [
      "notification:read",
      "notification:create",
      "notification:delete",
      "notification:manage"
    ],
    "services": [
      "NotificationService"
    ]
  },

  "requires": {
    "permissions": ["auth:verify", "user:read"],
    "events": []
  },

  "tier": {
    "minimum": "free",
    "features": {
      "free": ["in_app_notifications"],
      "starter": ["email_notifications"],
      "professional": ["sms_notifications", "push_notifications"],
      "business": ["scheduled_notifications", "bulk_notifications"],
      "enterprise": ["custom_channels", "notification_api"]
    }
  },

  "lifecycle": {
    "install": "lifecycle/install.ts",
    "uninstall": "lifecycle/uninstall.ts",
    "activate": "lifecycle/activate.ts",
    "deactivate": "lifecycle/deactivate.ts",
    "upgrade": "lifecycle/upgrade.ts"
  },

  "admin": {
    "menu": {
      "label": "Notifications",
      "icon": "ph-bell",
      "route": "/admin/notifications",
      "order": 80,
      "hidden": false
    }
  },

  "settings": {
    "schema": "settings.schema.json",
    "defaults": {
      "emailProvider": "smtp",
      "emailEnabled": true,
      "inAppEnabled": true,
      "smsEnabled": false,
      "pushEnabled": false,
      "batchDelay": 5000,
      "maxRetries": 3,
      "retryDelay": 60000,
      "digestEnabled": false,
      "digestInterval": "daily"
    }
  }
}
